n, m = map(int, input().split())
grid = [input() for _ in range(n)]

for i in range(n):
    row = ''
    for j in range(m):
        if grid[i][j] == '*':
            row += '*'
            continue
        cnt = 0
        for di in (-1, 0, 1):
            for dj in (-1, 0, 1):
                if di == 0 and dj == 0:
                    continue
                ni, nj = i + di, j + dj
                # 격자 범위 안에 있고 폭탄인지 확인
                if 0 <= ni < n and 0 <= nj < m and grid[ni][nj] == '*':
                    cnt += 1
        row += str(cnt)
    print(row)

n, m = map(int, input().split())
mat = [list(map(int, input().split())) for _ in range(n)]

result = []
for i, row in enumerate(mat):
    if i % 2 == 0:
        result.extend(row)              # 짝수 행: 왼쪽 -> 오른쪽
    else:
        result.extend(reversed(row))    # 홀수 행: 오른쪽 -> 왼쪽

print(' '.join(map(str, result)))
